public class TicketBookingService
{
    private readonly TicketContext _ticketContext;

    public TicketBookingService(TicketContext ticketContext) =>
        this._ticketContext = ticketContext ?? throw new ArgumentNullException(nameof(ticketContext));

    public async Task<bool> BookTicketsAsync(int eventId, int quantity)
    {
        var availableSeats = await this.GetAvailableSeatsCountAsync(eventId);

        if (availableSeats < quantity)
            return false;

        var ticketBookings = Enumerable
            .Range(0, quantity)
            .Select(_ => new TicketBooking
            {
                EventId = eventId,
                BookingDate = DateTime.Now,
            });

        await this._ticketContext.TicketBookings.AddRangeAsync(ticketBookings);
        return await this._ticketContext.SaveChangesAsync() > 0;
    }

    public async Task<int> GetAvailableSeatsCountAsync(int eventId) => 
        (await this._ticketContext
            .EventSeats
            .Where(x => x.EventId == eventId && !x.IsSoldOut)
            .Select(x => x.Quantity - x.SoldTicketsCount)
            .FirstOrDefaultAsync()) ?? 0;
}

